"""
azureocr.__init__
~~~~~~~~~~~~~~~~~

A Python client for Microsoft Azure OCR
"""

__author__ = "Max Drexler"
__email__ = "mndrexler@wisc.edu"


from enum import Enum
import json
import os
from typing import Any, Dict, List, Optional, Tuple, Union
from urllib.parse import urlencode

import requests
import validators
from dotenv import load_dotenv

from azvision.models import VisionResponse


__all__ = [
    "VisionFeatures",
    "RequestException",
    "MissingVariableException",
    "ComputerVisionClient",
    "scan",
]


CV_URL_PATH = "/computervision/imageanalysis:analyze"
DEF_API_VERSION = "2024-02-01"


class VisionFeatures(Enum):
    TAGS = "tags"
    OBJECTS = "objects"
    CAPTION = "caption"
    DENSECAPTION = "denseCaptions"
    READ = "read"
    SMARTCROP = "smartCrops"
    PEOPLE = "people"


class _ImageType(Enum):
    URL = "url"
    FILE = "file"
    MEM = "mem"


class RequestException(Exception):
    """Errors that occur while requesting"""


class MissingVariableException(Exception):
    """Missing environment variables"""


def _get_img_type(img: Any) -> _ImageType:
    if isinstance(img, str):
        if validators.url(img):
            return _ImageType.URL
        elif os.path.isfile(img):
            return _ImageType.FILE
        else:
            raise ValueError(f"Image: '{img}' is str, but not a file or url!")
    else:
        return _ImageType.MEM


def _load_service_options(env_path: Optional[str] = None) -> Tuple[str, str]:
    if env_path is not None:
        load_dotenv(env_path)
    key = os.getenv("VISION_KEY", None)
    endpoint = os.getenv("VISION_ENDPOINT", None)
    if key is None or endpoint is None:
        raise MissingVariableException(
            "Missing VISION_KEY and/or VISION_ENDPOINT environment variables!"
        )
    return key, endpoint


class ComputerVisionClient:
    def __init__(self, env_path: Optional[str] = None) -> None:
        self.__key, self.__endpoint = _load_service_options(env_path)
        self._language = "en"
        self._features: List[VisionFeatures] = []
        self._api_version = DEF_API_VERSION

    @property
    def api_version(self) -> str:
        return self._api_version

    @api_version.setter
    def api_version(self, new_version: str) -> None:
        self._api_version = new_version

    @property
    def language(self) -> str:
        return self._language

    @language.setter
    def language(self, new_lang: str) -> None:
        self._language = new_lang

    @property
    def features(self) -> List[VisionFeatures]:
        return self._features

    def add_feature(self, feature: Union[str, VisionFeatures]) -> None:
        new_feat = VisionFeatures(feature)
        if new_feat not in self._features:
            self._features.append(new_feat)

    def remove_feature(self, feature: Union[str, VisionFeatures]) -> None:
        new_feat = VisionFeatures(feature)
        if new_feat in self._features:
            self._features.remove(new_feat)

    def _construct_headers(self, img_type: _ImageType) -> Dict:
        if img_type == _ImageType.URL:
            content_type = "application/json"
        else:
            content_type = "application/octet-stream"
        return {
            "Content-Type": content_type,
            "Ocp-Apim-Subscription-Key": self.__key,
        }

    def _construct_url(self) -> str:
        url_base = f"{self.__endpoint.strip('/')}/{CV_URL_PATH}?"
        feat_list = (
            self._features
            if len(self._features) > 0
            else [VisionFeatures.READ]
        )
        params = {
            "api-version": self._api_version,
            "language": self._language,
            "model-version": "latest",
            "features": ",".join([feat.value for feat in feat_list]),
        }
        return url_base + urlencode(params)

    def _construct_body(
        self, image: Any, img_type: _ImageType
    ) -> Union[str, bytes]:
        if img_type == _ImageType.URL:
            body = json.dumps({"url": image})
        elif img_type == _ImageType.FILE:
            with open(image, "rb") as f:
                body = f.read()
        else:
            body = bytes(image)
        return body

    def scan(self, image: Any) -> VisionResponse:
        img_type = _get_img_type(image)
        headers = self._construct_headers(img_type)
        url = self._construct_url()
        body = self._construct_body(image, img_type)

        resp = requests.post(url=url, headers=headers, data=body)
        res = resp.json()
        if "error" in res:
            raise RequestException(
                f"[{res['error']['code']}]({resp.status_code}):"
                f"'{res['error']['message']}"
            )
        return VisionResponse(**res)


def scan(
    img: Any,
    key: Optional[str] = None,
    language: Optional[str] = None,
    env_file: Optional[str] = None,
    features: Optional[List[VisionFeatures]] = None,
    endpoint: Optional[str] = None,
) -> VisionResponse:
    if key is not None and endpoint is not None:
        os.environ["VISION_KEY"] = key
        os.environ["VISION_ENDPOINT"] = endpoint

    client = ComputerVisionClient(env_file)
    client.language = language
    #for feat in features:
    #    client.add_feature(feat)

    return client.scan(img)
